pub type Escrow {
  beneficiary: ByteArray,
  deadline: Int,
}

validator escrow_v2 {
  spend(_datum: Option<Escrow>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) -> Bool {
    let found =
      list.any(self.outputs, fn(out) {
        when out.datum is {
          InlineDatum(_raw) -> out.value == out.value
          _ -> False
        }
      })
    found
  }
}

